function SpeedTestWidget() {
  const [running, setRunning] = React.useState(false);
  const [done, setDone] = React.useState(false);
  const [speed, setSpeed] = React.useState(null);

  function runTest() {
    setRunning(true);
    setDone(false);
    setSpeed(null);
    setTimeout(() => {
      setRunning(false);
      setDone(true);
      setSpeed((Math.random() * 900 + 50).toFixed(1));
    }, 2500);
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>Internet Speed Test</h3>
      {done && speed && (
        <div style={{ textAlign: 'center', marginBottom: 16 }}>
          <div style={{ fontSize: 32, fontWeight: 700, color: '#22c55e' }}>{speed} Mbps</div>
          <div style={{ fontSize: 12, color: '#94a3b8' }}>Download Speed</div>
        </div>
      )}
      <button
        onClick={runTest}
        disabled={running}
        style={{
          padding: '10px 20px',
          borderRadius: 8,
          border: 'none',
          background: running ? '#334155' : '#3b82f6',
          color: '#fff',
          fontWeight: 600,
          cursor: running ? 'not-allowed' : 'pointer',
          fontFamily: 'system-ui, sans-serif'
        }}
      >
        {running ? 'Testing...' : done ? 'Run Again' : 'Start Test'}
      </button>
      {running && (
        <div style={{ marginTop: 16, fontSize: 12, color: '#94a3b8' }}>Measuring bandwidth...</div>
      )}
    </div>
  );
}
render(<SpeedTestWidget/>);
